    63→// TODO: Optimize this, just like the stats endpoint!
    64→func (data *APIMetricData) AddStats() {
    65→	n := 0
    66→	sum, min, max := 0.0, math.MaxFloat64, -math.MaxFloat64
    67→	for _, x := range data.Data {
    68→		if x.IsNaN() {
    69→			continue
    70→		}
    71→
    72→		n += 1
    73→		sum += float64(x)
    74→		min = math.Min(min, float64(x))
    75→		max = math.Max(max, float64(x))
    76→	}
    77→
    78→	if n > 0 {
    79→		avg := sum / float64(n)
    80→		data.Avg = schema.Float(avg)
    81→		data.Min = schema.Float(min)
    82→		data.Max = schema.Float(max)
    83→	} else {
    84→		data.Avg, data.Min, data.Max = schema.NaN, schema.NaN, schema.NaN
    85→	}
    86→}
    87→
    88→func (data *APIMetricData) ScaleBy(f schema.Float) {
    89→	if f == 0 || f == 1 {
    90→		return
    91→	}
    92→
    93→	data.Avg *= f
    94→	data.Min *= f
    95→	data.Max *= f
    96→	for i := 0; i < len(data.Data); i++ {
    97→		data.Data[i] *= f
    98→	}
    99→}
