   101→func (data *APIMetricData) PadDataWithNull(ms *metricstore.MemoryStore, from, to int64, metric string) {
   102→	minfo, ok := ms.Metrics[metric]
   103→	if !ok {
   104→		return
   105→	}
   106→
   107→	if (data.From / minfo.Frequency) > (from / minfo.Frequency) {
   108→		padfront := int((data.From / minfo.Frequency) - (from / minfo.Frequency))
   109→		ndata := make([]schema.Float, 0, padfront+len(data.Data))
   110→		for range padfront {
   111→			ndata = append(ndata, schema.NaN)
   112→		}
   113→		for j := 0; j < len(data.Data); j++ {
   114→			ndata = append(ndata, data.Data[j])
   115→		}
   116→		data.Data = ndata
   117→	}
   118→}
