   148→// handleQuery godoc
   149→// @summary    Query metrics
   150→// @tags query
   151→// @description This endpoint allows the users to retrieve data from the
   152→// in-memory database. The CCMS will return data in JSON format for the
   153→// specified interval requested by the user
   154→// @accept      json
   155→// @produce     json
   156→// @param       request body     api.ApiQueryRequest  true "API query payload object"
   157→// @success     200            {object} api.ApiQueryResponse  "API query response object"
   158→// @failure     400            {object} api.ErrorResponse       "Bad Request"
   159→// @failure     401   		   {object} api.ErrorResponse       "Unauthorized"
   160→// @failure     403            {object} api.ErrorResponse       "Forbidden"
   161→// @failure     500            {object} api.ErrorResponse       "Internal Server Error"
   162→// @security    ApiKeyAuth
   163→// @router      /query/ [get]
   164→func handleQuery(rw http.ResponseWriter, r *http.Request) {
   165→	var err error
   166→	ver := r.URL.Query().Get("version")
   167→	if ver == "" {
   168→		ver = "v2"
   169→	}
   170→	req := APIQueryRequest{WithStats: true, WithData: true, WithPadding: true}
   171→	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
   172→		handleError(err, http.StatusBadRequest, rw)
   173→		return
   174→	}
   175→
   176→	ms := metricstore.GetMemoryStore()
   177→
   178→	response := APIQueryResponse{
   179→		Results: make([][]APIMetricData, 0, len(req.Queries)),
   180→	}
   181→	if req.ForAllNodes != nil {
   182→		nodes := ms.ListChildren([]string{req.Cluster})
   183→		for _, node := range nodes {
   184→			for _, metric := range req.ForAllNodes {
   185→				q := APIQuery{
   186→					Metric:   metric,
   187→					Hostname: node,
   188→				}
   189→				req.Queries = append(req.Queries, q)
   190→				response.Queries = append(response.Queries, q)
   191→			}
   192→		}
   193→	}
   194→
   195→	for _, query := range req.Queries {
   196→		sels := make([]util.Selector, 0, 1)
   197→		if query.Aggregate || query.Type == nil {
   198→			sel := util.Selector{{String: req.Cluster}, {String: query.Hostname}}
   199→			if query.Type != nil {
   200→				if len(query.TypeIds) == 1 {
   201→					sel = append(sel, util.SelectorElement{String: *query.Type + query.TypeIds[0]})
   202→				} else {
   203→					ids := make([]string, len(query.TypeIds))
   204→					for i, id := range query.TypeIds {
   205→						ids[i] = *query.Type + id
   206→					}
   207→					sel = append(sel, util.SelectorElement{Group: ids})
   208→				}
   209→
   210→				if query.SubType != nil {
   211→					if len(query.SubTypeIds) == 1 {
   212→						sel = append(sel, util.SelectorElement{String: *query.SubType + query.SubTypeIds[0]})
   213→					} else {
   214→						ids := make([]string, len(query.SubTypeIds))
   215→						for i, id := range query.SubTypeIds {
   216→							ids[i] = *query.SubType + id
   217→						}
   218→						sel = append(sel, util.SelectorElement{Group: ids})
   219→					}
   220→				}
   221→			}
   222→			sels = append(sels, sel)
   223→		} else {
   224→			for _, typeID := range query.TypeIds {
   225→				if query.SubType != nil {
   226→					for _, subTypeID := range query.SubTypeIds {
   227→						sels = append(sels, util.Selector{
   228→							{String: req.Cluster},
   229→							{String: query.Hostname},
   230→							{String: *query.Type + typeID},
   231→							{String: *query.SubType + subTypeID},
   232→						})
   233→					}
   234→				} else {
   235→					sels = append(sels, util.Selector{
   236→						{String: req.Cluster},
   237→						{String: query.Hostname},
   238→						{String: *query.Type + typeID},
   239→					})
   240→				}
   241→			}
   242→		}
   243→
   244→		// log.Printf("query: %#v\n", query)
   245→		// log.Printf("sels: %#v\n", sels)
   246→
   247→		res := make([]APIMetricData, 0, len(sels))
   248→		for _, sel := range sels {
   249→			data := APIMetricData{}
   250→
   251→			data.Data, data.From, data.To, data.Resolution, err = ms.Read(sel, query.Metric, req.From, req.To, query.Resolution)
   252→			if err != nil {
   253→				// Skip Error If Just Missing Host or Metric, Continue
   254→				// Empty Return For Metric Handled Gracefully By Frontend
   255→				if err != metricstore.ErrNoHostOrMetric {
   256→					msg := err.Error()
   257→					data.Error = &msg
   258→					res = append(res, data)
   259→				} else {
   260→					cclog.Warnf("failed to fetch '%s' from host '%s' (cluster: %s): %s", query.Metric, query.Hostname, req.Cluster, err.Error())
   261→				}
   262→				continue
   263→			}
   264→
   265→			if req.WithStats {
   266→				data.AddStats()
   267→			}
   268→			if query.ScaleFactor != 0 {
   269→				data.ScaleBy(query.ScaleFactor)
   270→			}
   271→			if req.WithPadding {
   272→				data.PadDataWithNull(ms, req.From, req.To, query.Metric)
   273→			}
   274→			if !req.WithData {
   275→				data.Data = nil
   276→			}
   277→			res = append(res, data)
   278→		}
   279→		response.Results = append(response.Results, res)
   280→	}
   281→
   282→	rw.Header().Set("Content-Type", "application/json")
   283→	bw := bufio.NewWriter(rw)
   284→	defer bw.Flush()
   285→	if err := json.NewEncoder(bw).Encode(response); err != nil {
   286→		log.Print(err)
   287→		return
   288→	}
   289→}
