   291→// handleFree godoc
   292→// @summary
   293→// @tags free
   294→// @description This endpoint allows the users to free the Buffers from the
   295→// metric store. This endpoint offers the users to remove then systematically
   296→// and also allows then to prune the data under node, if they do not want to
   297→// remove the whole node.
   298→// @produce     json
   299→// @param       to        query    string        false  "up to timestamp"
   300→// @success     200            {string} string  "ok"
   301→// @failure     400            {object} api.ErrorResponse       "Bad Request"
   302→// @failure     401            {object} api.ErrorResponse       "Unauthorized"
   303→// @failure     403            {object} api.ErrorResponse       "Forbidden"
   304→// @failure     500            {object} api.ErrorResponse       "Internal Server Error"
   305→// @security    ApiKeyAuth
   306→// @router      /free/ [post]
   307→func freeMetrics(rw http.ResponseWriter, r *http.Request) {
   308→	rawTo := r.URL.Query().Get("to")
   309→	if rawTo == "" {
   310→		handleError(errors.New("'to' is a required query parameter"), http.StatusBadRequest, rw)
   311→		return
   312→	}
   313→
   314→	to, err := strconv.ParseInt(rawTo, 10, 64)
